// Read/save offset via Static Data
const staticData = $getWorkflowStaticData('global');
const offset = staticData.telegramOffset || 0;
return [{ json: { offset } }];

// Parse updates — filter only messages for our chat_id
const data = $input.first().json;
const updates = data.result || [];
const allowedChatId = parseInt($env.N8N_TELEGRAM_CHAT_ID);

if (updates.length === 0) return [];

// Update offset
const staticData = $getWorkflowStaticData('global');
const lastUpdate = updates[updates.length - 1];
staticData.telegramOffset = lastUpdate.update_id + 1;

// Filter and extract commands
const messages = [];
for (const upd of updates) {
  const msg = upd.message || upd.edited_message;
  if (!msg) continue;
  if (msg.chat.id !== allowedChatId) continue;

  const text = (msg.text || '').trim();
  const command = text.split(' ')[0].toLowerCase();
  const args = text.split(' ').slice(1).join(' ');

  messages.push({ json: {
    update_id: upd.update_id,
    chat_id: msg.chat.id,
    from: msg.from?.username || msg.from?.first_name || 'Unknown',
    text,
    command,
    args
  }});
}

return messages;

const https = require('https');
const fs = require('fs');
const token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
const ca = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/ca.crt');
const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'kubernetes.default.svc.cluster.local',
    port: 443,
    path: '/api/v1/nodes',
    method: 'GET',
    headers: { 'Authorization': 'Bearer ' + token },
    ca: ca
  }, (res) => {
    let data = '';
    res.on('data', c => data += c);
    res.on('end', () => resolve(JSON.parse(data)));
  });
  req.on('error', reject);
  req.end();
});
return [{ json: result }];

const https = require('https');
const fs = require('fs');
const token = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/token', 'utf8').trim();
const ca = fs.readFileSync('/var/run/secrets/kubernetes.io/serviceaccount/ca.crt');
const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'kubernetes.default.svc.cluster.local',
    port: 443,
    path: '/api/v1/pods',
    method: 'GET',
    headers: { 'Authorization': 'Bearer ' + token },
    ca: ca
  }, (res) => {
    let data = '';
    res.on('data', c => data += c);
    res.on('end', () => resolve(JSON.parse(data)));
  });
  req.on('error', reject);
  req.end();
});
return [{ json: result }];

// Format node status
const nodes = $input.first().json.items || [];
let msg = '🖥️ <b>Cluster Nodes</b>\n\n';

for (const node of nodes) {
  const name = node.metadata.name;
  const ready = node.status.conditions?.find(c => c.type === 'Ready');
  const status = ready?.status === 'True' ? '✅' : '🔴';
  const roles = Object.keys(node.metadata.labels || {})
    .filter(k => k.startsWith('node-role.kubernetes.io/'))
    .map(k => k.replace('node-role.kubernetes.io/', ''))
    .join(', ') || 'worker';
  const cpu = node.status.capacity?.cpu || '?';
  const mem = node.status.capacity?.memory || '?';
  const zone = node.metadata.labels?.['topology.kubernetes.io/zone'] || '?';

  msg += `${status} <code>${name}</code> [${roles}]\n`;
  msg += `   Zone: ${zone} | CPU: ${cpu} | Mem: ${parseInt(mem) > 0 ? Math.round(parseInt(mem)/1024/1024) + 'Gi' : mem}\n`;
}

return [{ json: { message: msg, chat_id: $('Parse Commands').first().json.chat_id } }];

// Format problem pods
const pods = $input.first().json.items || [];
const problemPods = pods.filter(p => {
  const phase = p.status.phase;
  if (phase === 'Running' || phase === 'Succeeded') {
    // Check containers for restarts > 5
    const containers = p.status.containerStatuses || [];
    return containers.some(c => c.restartCount > 5);
  }
  return phase !== 'Running' && phase !== 'Succeeded';
});

let msg = `📦 <b>Pod Status</b>\n`;
msg += `Total: ${pods.length} pods | Issues: ${problemPods.length}\n\n`;

if (problemPods.length === 0) {
  msg += '✅ All pods healthy!';
} else {
  msg += '⚠️ <b>Problem Pods:</b>\n';
  for (const pod of problemPods.slice(0, 10)) {
    const name = pod.metadata.name;
    const ns = pod.metadata.namespace;
    const phase = pod.status.phase;
    const restarts = (pod.status.containerStatuses || []).reduce((sum, c) => sum + (c.restartCount || 0), 0);
    msg += `🔴 <code>${ns}/${name}</code>\n   Phase: ${phase} | Restarts: ${restarts}\n`;
  }
}

return [{ json: { message: msg, chat_id: $('Parse Commands').first().json.chat_id } }];

const chatId = $input.first().json.chat_id;
const msg = `🤖 <b>DevOps Lab Bot</b>

Available commands:

/status — cluster node status
/pods — all pods status (problem pods highlighted)
/help — this help

⚙️ Bot runs in polling mode. Requests are processed once per minute.`;
return [{ json: { message: msg, chat_id: chatId } }];
